class bfm;
	virtual my_interface.master master;
	virtual my_interface.slave slave;
endclass

function new(
	virtual my_interface.master master,
	virtual my_interface.slave slave
);
	this.master = master;
	this.slave = slave;
endfunction

interface my_interface;
	logic signal;
	modport master(output signal);
	modport slave(input signal);
endinterface
